import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

Deno.serve(async (req) => {
  const reqId = Math.random().toString(36).substring(7);
  console.log(`[INTEGRITY_AUDIT][${reqId}] Audit Request Received.`);

  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  );

  try {
    // 1. EXTRACT LOW-IMPORTANCE WORDS FROM DATABASE
    console.log(`[AUDIT][${reqId}] Extracting words with importance <= 5 from JSONB columns...`);

    // We use a specific query to flatten the JSONB 'words' array and filter by importance
    const { data: dbWordsRaw, error: dbErr } = await supabase.from('processed_words').select('words');
    if (dbErr) throw dbErr;

    const dbWordsMap = new Map(); // word -> count
    (dbWordsRaw || []).forEach(row => {
       if (Array.isArray(row.words)) {
         row.words.forEach((item: any) => {
           if (item.importance <= 5) {
             const cleanWord = item.word ? item.word.trim() : 'NULL_VAL';
             dbWordsMap.set(cleanWord, (dbWordsMap.get(cleanWord) || 0) + 1);
           }
         });
       }
    });
    console.log(`[AUDIT][${reqId}] Found ${dbWordsMap.size} unique words in DB with importance <= 5.`);

    // 2. EXTRACT WORDS FROM STORAGE FILES
    console.log(`[AUDIT][${reqId}] Listing files in inspection_bucket...`);
    const { data: storageFiles, error: listErr } = await supabase.storage.from('inspection_bucket').list('', { limit: 1000 });
    if (listErr) throw listErr;

    const txtFiles = (storageFiles || []).filter(f => f.name.endsWith('.txt'));
    console.log(`[AUDIT][${reqId}] Found ${txtFiles.length} files in bucket. Downloading and parsing...`);

    const storageWordsMap = new Map(); // word -> file_origin
    const fileAnalysis = [];

    for (const file of txtFiles) {
      const { data: blob, error: dlErr } = await supabase.storage.from('inspection_bucket').download(file.name);
      if (dlErr) {
        console.error(`[AUDIT][${reqId}] Failed to download ${file.name}`);
        continue;
      }

      const text = await blob.text();
      const lines = text.split('\n').filter(l => l.trim().length > 0);

      lines.forEach(line => {
        const match = line.match(/^(\d+)\.\s+(.+)$/);
        if (match) {
          const word = match[2].trim();
          storageWordsMap.set(word, file.name);
        }
      });

      fileAnalysis.push({ name: file.name, word_count: lines.length });
    }
    console.log(`[AUDIT][${reqId}] Extracted ${storageWordsMap.size} total words from physical storage files.`);

    // 3. COMPARISON LOGIC
    const matches = [];
    const missingFromStorage = []; // In DB (imp <=5) but not in any file
    const missingFromDB = [];      // In file but not in DB (imp <=5)

    // Check DB -> Storage
    for (const word of dbWordsMap.keys()) {
      if (storageWordsMap.has(word)) {
        matches.push(word);
      } else {
        missingFromStorage.push(word);
      }
    }

    // Check Storage -> DB
    for (const word of storageWordsMap.keys()) {
      if (!dbWordsMap.has(word)) {
        missingFromDB.push({ word, file: storageWordsMap.get(word) });
      }
    }

    // 4. REPORT GENERATION
    const report = {
      summary: {
        total_db_low_importance_words: dbWordsMap.size,
        total_physical_storage_words: storageWordsMap.size,
        total_perfect_matches: matches.length,
        discrepancy_count: missingFromStorage.length + missingFromDB.length
      },
      storage_integrity: {
        files_scanned: txtFiles.length,
        average_words_per_file: (storageWordsMap.size / (txtFiles.length || 1)).toFixed(1)
      },
      missing_data: {
        db_words_not_in_storage_count: missingFromStorage.length,
        db_words_not_in_storage_sample: missingFromStorage.slice(0, 20),
        storage_words_not_in_db_count: missingFromDB.length,
        storage_words_not_in_db_sample: missingFromDB.slice(0, 20)
      },
      conclusion: ""
    };

    if (missingFromDB.length > 0) {
      report.conclusion = `WARNING: ${missingFromDB.length} words found in storage files are NOT marked as importance <= 5 in your DB. This indicates your setup script used different criteria or old data.`;
    } else if (missingFromStorage.length > 0) {
      report.conclusion = `WARNING: ${missingFromStorage.length} words in DB are missing from Storage. Your upload script might have timed out.`;
    } else {
      report.conclusion = "INTEGRITY VERIFIED: Storage and Database are perfectly synchronized.";
    }

    return new Response(JSON.stringify(report, null, 2), {
      headers: { 'Content-Type': 'application/json' }
    });

  } catch (err) {
    console.error(`[AUDIT][${reqId}][FATAL]`, err);
    return new Response(JSON.stringify({ error: err.message }), { status: 500 });
  }
});

