2232 |                     // If errors remain, update list and Prompt user
2233 |                     currentErrors = scanData.errors;
2234 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2235 |                         // Recursively fix the *new* first error (since layout changed)
2236 |                         return await fixNext(0);
2237 |                     } else {
2238 |                         return false;
2239 |                     }
2240 |                 }
2241 | 
2242 |             } catch (e) {
2243 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2244 |                     return await fixNext(index);
2245 |                 } else {
2246 |                     return false;
2247 |                 }
2248 |             }
2249 |         }
2250 | 
2251 |         return await fixNext(0);
