4893 |     function formatBytes(bytes) {
4894 |         if (!bytes) return '0 B';
4895 |         const k = 1024;
4896 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4897 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4898 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
