4901 |     function timeAgo(dateString) {
4902 |         const date = new Date(dateString);
4903 |         const now = new Date();
4904 |         const seconds = Math.floor((now - date) / 1000);
4905 |         if (seconds < 10) return 'just now';
4906 |         if (seconds < 60) return seconds + 's ago';
4907 |         const minutes = Math.floor(seconds / 60);
4908 |         if (minutes < 60) return minutes + 'm ago';
4909 |         const hours = Math.floor(minutes / 60);
4910 |         if (hours < 24) return hours + 'h ago';
4911 |         return date.toLocaleDateString();
4912 |     }
