5111 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5112 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5113 |         
5114 |         const navItems = document.querySelectorAll('.nav-item');
5115 |         switchTab(tabId, navItems[navIndex]);
5116 | 
5117 |         const scrollContainer = document.querySelector('.main-view');
5118 |         let retryCount = 0;
5119 |         const MAX_RETRIES = 5;
5120 | 
5121 |         const attemptNavigation = async () => {
5122 |             const element = document.querySelector(selector);
5123 |             
5124 |             if (element) {
5125 |                 console.log("[DeepJump] Element found. Scrolling...");
5126 |                 
5127 |                 // Wait for any tab transition animations
5128 |                 await new Promise(r => setTimeout(r, 300));
5129 | 
5130 |                 let offsetTop = 0;
5131 |                 let curr = element;
5132 |                 while (curr && curr !== scrollContainer) {
5133 |                     offsetTop += curr.offsetTop;
5134 |                     curr = curr.offsetParent;
5135 |                 }
5136 | 
5137 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5138 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5139 | 
5140 |                 // Visual Highlight
5141 |                 element.style.transition = 'all 0.5s ease';
5142 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5143 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5144 |                 setTimeout(() => {
5145 |                     element.style.backgroundColor = '';
5146 |                     element.style.boxShadow = '';
5147 |                 }, 3000);
5148 |                 
5149 |                 console.groupEnd();
5150 |                 return true;
5151 |             }
5152 | 
5153 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5154 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5155 |                 retryCount++;
5156 |                 showGlobalToast("🔍 Searching deeper...");
5157 |                 
5158 |                 await loadMoreFn(); 
5159 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5160 |                 return attemptNavigation();
5161 |             }
5162 | 
5163 |             console.error("[DeepJump] Failed: Element not found after retries.");
5164 |             showGlobalToast("Entry not found in recent history.", true);
5165 |             console.groupEnd();
5166 |             return false;
5167 |         };
5168 | 
5169 |         setTimeout(attemptNavigation, 100);
5170 |     }
