6453 |     async function deleteSelectedHistory() {
6454 |         const checkboxes = Array.from(document.querySelectorAll('.history-check:checked'));
6455 |         if (!checkboxes.length) return;
6456 | 
6457 |         const idsToDelete = checkboxes.map(cb => cb.value);
6458 |         
6459 |         // Find the oldest record among the selection to determine rollback target
6460 |         // dbHistory is sorted newest -> oldest
6461 |         let oldestSelectedIndex = -1;
6462 |         checkboxes.forEach(cb => {
6463 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
6464 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
6465 |         });
6466 | 
6467 |         // The target is the first record older than our selection that isn't also being deleted
6468 |         let rollbackTarget = null;
6469 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
6470 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
6471 |                 rollbackTarget = dbHistory[i];
6472 |                 break;
6473 |             }
6474 |         }
6475 | 
6476 |         let msg = `Delete ${checkboxes.length} selected records?`;
6477 |         if (rollbackTarget) {
6478 |             msg += `\n\n⚠️ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
6479 |         }
6480 | 
6481 |         if (!confirm(msg)) return;
6482 | 
6483 |         showGlobalToast("Batch Deleting & Rolling back...");
6484 | 
6485 |         // 1. Perform Rollback
6486 |         if (rollbackTarget) {
6487 |             await fetch(CONFIG.funcUrl, {
6488 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
6489 |                 body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
