6492 | 
6493 |         // 2. Perform Batch Deletion
6494 |         await Promise.all(idsToDelete.map(id => 
6495 |             fetch(CONFIG.funcUrl, {
6496 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
6497 |                 body: apiBody({ action: 'delete_history', id: id })
6498 |             })
6499 |         ));
6500 | 
6501 |         fetchState(true);
