7277 |     function extractTableNames(sql) {
7278 |         if (!sql) return [];
7279 |         const tables = [];
7280 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7281 |         
7282 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7283 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7284 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7285 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7286 | 
7287 |         let match;
7288 |         while ((match = fromRegex.exec(sql)) !== null) {
7289 |             const name = match[1];
7290 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7291 |                 tables.push(name);
7292 |             }
7293 |         }
7294 |         
7295 |         while ((match = metaRegex.exec(sql)) !== null) {
7296 |             const name = match[1];
7297 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7298 |                 tables.push(name);
7299 |             }
7300 |         }
7301 | 
7302 |         return tables;
7303 |     }
