        if (result == android.media.AudioManager.AUDIOFOCUS_REQUEST_GRANTED) {
            isFocusHeld = true
            DebugLogger.log("SESSION", "Focus Secured")
            mediaSession?.isActive = true
            startSilentLoop()
        }
    }
    isClaiming = false
