async function runPatch(actionType) {
    if (isPerformingAction) return;
    isPerformingAction = true;

    const btns = ['btn-patch-test', 'btn-patch-stage', 'btn-patch-prod'].map(id => document.getElementById(id));
    btns.forEach(b => { if(b) { b.disabled = true; b.style.opacity = '0.5'; } });

    FILE_OP_MAP = {}; 
    document.querySelectorAll('.op-row').forEach(el => {
        el.style.borderLeft = ''; el.style.backgroundColor = '';
    });

    let inputVal = document.getElementById('json-input').value;
    let payload = {};

    if (actionType === 'patch' || actionType === 'commit_prod') {
        try {
            const parsed = smartJSONParse(inputVal);
            payload = Array.isArray(parsed) ? parsed : (parsed.operations || []);
        } catch(e) {
            const errorMsg = `JSON PARSE ERROR:\n${e.message}`;
            addTerminalCard(null, { error: errorMsg });
            isPerformingAction = false;
            btns.forEach(b => { if(b) { b.disabled = false; b.style.opacity = '1'; } });
            return; 
        }
    }

    if (actionType === 'commit_prod') {
        const vName = prompt("Version Name (e.g. v1.0):");
        if (vName === null) {
            isPerformingAction = false;
            btns.forEach(b => { if(b) { b.disabled = false; b.style.opacity = '1'; } });
            return;
        }
        payload.version_name = vName || "v1.0";
    }

    const termId = addTerminalCard(null, { loading: true });

    try {
        if (Array.isArray(payload)) {
            for (let op of payload) {
                if (op.file_path) op.file_path = op.file_path.replace(/\\/g, '/').replace(/\/\//g, '/');
                if (op.file_path === 'index.ts' && CONFIG.efDeploymentMode === 'default') {
                    const resolved = await resolveEdgeFunctionPath(op.file_path);
                    if (!resolved) throw new Error("Operation Cancelled");
                    op.file_path = resolved;
                    op.is_resolved_ef = true;
                }
                const isEfPath = op.is_resolved_ef || (op.file_path && op.file_path.startsWith('supabase/functions/'));
                if (CONFIG.projectPath && op.file_path && !isEfPath) {
                    let cleanPath = op.file_path.trim().replace(/^\/+/, '');
                    if (!cleanPath.startsWith(CONFIG.projectPath)) op.file_path = CONFIG.projectPath + cleanPath;
                }
            }
        }

        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ 
                action: actionType, 
                operations: payload, 
                version_name: payload.version_name,
                project_path: CONFIG.projectPath,
                auto_sanity: CONFIG.autoSanity
            })
        });
        const data = await res.json();
        updateTerminalCard(termId, data, payload, true);

        if(data.success) {
            if(actionType === 'patch') setTimeout(() => bundleAndPreview(null), 1500);
            setTimeout(() => { fetchState(false, false); fetchFileList(); }, 1000);
        }
    } catch (e) {
        updateTerminalCard(termId, { error: e.message });
    } finally {
        isPerformingAction = false;
        btns.forEach(b => { if(b) { b.disabled = false; b.style.opacity = '1'; } });
    }
}
}

