4902 |     function formatBytes(bytes) {
4903 |         if (!bytes) return '0 B';
4904 |         const k = 1024;
4905 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4906 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4907 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4908 |     }
