4910 |     function timeAgo(dateString) {
4911 |         const date = new Date(dateString);
4912 |         const now = new Date();
4913 |         const seconds = Math.floor((now - date) / 1000);
4914 |         if (seconds < 10) return 'just now';
4915 |         if (seconds < 60) return seconds + 's ago';
4916 |         const minutes = Math.floor(seconds / 60);
4917 |         if (minutes < 60) return minutes + 'm ago';
4918 |         const hours = Math.floor(minutes / 60);
4919 |         if (hours < 24) return hours + 'h ago';
4920 |         return date.toLocaleDateString();
4921 |     }
