5120 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5121 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5122 |         
5123 |         const navItems = document.querySelectorAll('.nav-item');
5124 |         switchTab(tabId, navItems[navIndex]);
5125 | 
5126 |         const scrollContainer = document.querySelector('.main-view');
5127 |         let retryCount = 0;
5128 |         const MAX_RETRIES = 5;
5129 | 
5130 |         const attemptNavigation = async () => {
5131 |             const element = document.querySelector(selector);
5132 |             
5133 |             if (element) {
5134 |                 console.log("[DeepJump] Element found. Scrolling...");
5135 |                 
5136 |                 // Wait for any tab transition animations
5137 |                 await new Promise(r => setTimeout(r, 300));
5138 | 
5139 |                 let offsetTop = 0;
5140 |                 let curr = element;
5141 |                 while (curr && curr !== scrollContainer) {
5142 |                     offsetTop += curr.offsetTop;
5143 |                     curr = curr.offsetParent;
5144 |                 }
5145 | 
5146 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5147 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5148 | 
5149 |                 // Visual Highlight
5150 |                 element.style.transition = 'all 0.5s ease';
5151 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5152 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5153 |                 setTimeout(() => {
5154 |                     element.style.backgroundColor = '';
5155 |                     element.style.boxShadow = '';
5156 |                 }, 3000);
5157 |                 
5158 |                 console.groupEnd();
5159 |                 return true;
5160 |             }
5161 | 
5162 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5163 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5164 |                 retryCount++;
5165 |                 showGlobalToast("🔍 Searching deeper...");
5166 |                 
5167 |                 await loadMoreFn(); 
5168 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5169 |                 return attemptNavigation();
5170 |             }
5171 | 
5172 |             console.error("[DeepJump] Failed: Element not found after retries.");
5173 |             showGlobalToast("Entry not found in recent history.", true);
5174 |             console.groupEnd();
5175 |             return false;
5176 |         };
