6263 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
6264 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
6265 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
6266 |         }
6267 | 
6268 |         diffLeft.setValue("Loading...", -1);
6269 |         diffRight.setValue("Loading...", -1);
6270 | 
6271 |         try {
6272 |             let leftContent = "", rightContent = "";
6273 | 
6274 |             if (forcedLeft !== null && forcedRight !== null) {
6275 |                 leftContent = forcedLeft;
6276 |                 rightContent = forcedRight;
6277 |             } else {
6278 |                 const rightRef = data.commit_sha || 'HEAD';
6279 |                 const leftRef = rightRef + '^';
6280 | 
6281 |                 const fetchFile = async (ref) => {
6282 |                     const res = await fetch(CONFIG.funcUrl, {
6283 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
6284 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
6285 |                     });
6286 |                     const d = await res.json();
6287 |                     return d.content ? b64DecodeUnicode(d.content) : '';
6288 |                 };
6289 | 
6290 |                 const results = await Promise.all([
6291 |                     fetchFile(leftRef).catch(() => ""),
6292 |                     fetchFile(rightRef).catch(() => "")
6293 |                 ]);
6294 |                 leftContent = results[0];
6295 |                 rightContent = results[1];
6296 |             }
6297 | 
6298 |             let mode = "ace/mode/text";
6299 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
6300 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
6301 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
