6310 | 
6311 |             const Range = ace.require('ace/range').Range;
6312 | 
6313 |             // Helper to get Range from String Index
6314 |             const getRangeFromText = (session, searchText) => {
6315 |                 const fullText = session.getValue();
6316 |                 // 1. Try Exact Match
6317 |                 let startIdx = fullText.indexOf(searchText);
6318 |                 
6319 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
6320 |                 if (startIdx === -1) {
6321 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
