6332 |                     return new Range(startRow, startCol, endRow, endCol);
6333 |                 }
6334 |                 return null;
6335 |             };
6336 |             
6337 |             const searchRemove = data.op.find_block || data.op.anchor;
6338 |             if(searchRemove) {
