7278 |     function extractTableNames(sql) {
7279 |         if (!sql) return [];
7280 |         const tables = [];
7281 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7282 |         
7283 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7284 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7285 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7286 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7287 | 
7288 |         let match;
7289 |         while ((match = fromRegex.exec(sql)) !== null) {
7290 |             const name = match[1];
7291 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7292 |                 tables.push(name);
7293 |             }
7294 |         }
7295 |         
7296 |         while ((match = metaRegex.exec(sql)) !== null) {
7297 |             const name = match[1];
7298 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7299 |                 tables.push(name);
7300 |             }
7301 |         }
7302 | 
7303 |         return tables;
7304 |     }
7305 | 
7306 |     function convertToCSV(resultObj) {
7307 |         const data = resultObj.data || [];
7308 |         if (!data.length) return '';
7309 |         
7310 |         const tables = extractTableNames(resultObj.sql);
7311 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7312 | 
7313 |         const headers = Object.keys(data[0]);
7314 |         const rows = data.map(row => 
7315 |             headers.map(header => {
7316 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7317 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7318 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7319 |             }).join(',')
7320 |         );
7321 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7322 |     }
