window.currentHudTab = 'console';
window.switchHudTab = (tab) => {
    window.currentHudTab = tab;
    document.getElementById('tab-console').classList.toggle('active', tab === 'console');
    document.getElementById('tab-network').classList.toggle('active', tab === 'network');
    document.getElementById('conduit-debug-list').style.display = tab === 'console' ? 'block' : 'none';
    document.getElementById('conduit-net-list').style.display = tab === 'network' ? 'block' : 'none';
    document.getElementById('hud-copy-all-btn').onclick = tab === 'console' ? window.copyAllPreviewLogs : window.copyAllPreviewNetwork;
};

window.clearHudData = () => {
    if(window.currentHudTab === 'console') { window.localLogs = []; window.updateLocalLogUI(); }
    else { window.localNetwork = []; window.updateLocalNetworkUI(); }
};

window.copyPreviewNetwork = (idx) => {
    const entry = window.localNetwork[idx];
    if(!entry) return;
    const text = JSON.stringify(entry, null, 2);
    navigator.clipboard.writeText(text).then(() => alert("Copied Request JSON"));
};

window.copyAllPreviewLogs = () => {
    const text = window.localLogs.map(l => `[${l.time}] ${l.msg}`).join('\n');
    navigator.clipboard.writeText(text).then(() => alert("Copied All Logs"));
};

window.copyAllPreviewNetwork = () => {
    const text = window.localNetwork.map(n => `${n.method} ${n.status} ${n.url} (${n.duration}ms)`).join('\n');
    navigator.clipboard.writeText(text).then(() => alert("Copied Network Trace"));
};

window.updateLocalLogUI = () => {
    list.innerHTML = window.localLogs.map((l, idx) => `
        <div class="debug-row log-${l.method}">
            <button class="line-copy-btn" onclick="window.copyPreviewLine(${idx})">Copy</button>
            <div class="debug-meta">
                <span>${l.method.toUpperCase()}</span>
                <span>${l.time}</span>
            </div>
            <div style="white-space:pre-wrap; word-break:break-all; line-height:1.4;">${l.msg}</div>
        </div>
    `).join('');
};

window.updateLocalNetworkUI = () => {
    const netList = document.getElementById('conduit-net-list');
    netList.innerHTML = window.localNetwork.map((n, idx) => `
        <div class="debug-row">
            <button class="line-copy-btn" onclick="window.copyPreviewNetwork(${idx})">Copy JSON</button>
            <details style="width:100%">
                <summary style="outline:none; list-style:none;">
                    <div class="net-grid">
                        <span style="color:#d946ef; font-weight:bold;">${n.method}</span>
                        <span style="color:${n.status >= 400 ? '#ef4444' : '#22c55e'};">${n.status}</span>
                        <span style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap; color:#aaa;">${n.url.split('/').pop() || n.url}</span>
                    </div>
                </summary>
                <div style="margin-top:8px; padding:8px; background:#000; border-radius:4px; font-size:9px; color:#666; overflow-x:auto;">
                    <b>URL:</b> ${n.url}<br>
                    <b>TIME:</b> ${n.duration}ms<br>
                    <b>RES:</b> ${typeof n.responseBody === 'object' ? JSON.stringify(n.responseBody) : n.responseBody}
                </div>
            </details>
        </div>
    `).join('');
};

window.updateLocalLogUI();
window.updateLocalNetworkUI();

