274 | suspend fun callConduitAction(payload: JSONObject): String = withContext(Dispatchers.IO) {
275 |     val client = OkHttpClient()
276 |     val body = payload.toString().toRequestBody("application/json".toMediaType())
277 |     val request = Request.Builder()
278 |         .url("https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/gemini-handler")
279 |         .post(body)
280 |         .build()
281 |     try { 
282 |         client.newCall(request).execute().use { it.body?.string() ?: "" } 
283 |     } catch (e: Exception) { 
284 |         "Error: ${e.message}" 
285 |     }
286 | }
