588 |         val candidates = jsonResp.optJSONArray("candidates") ?: return "AI Error: No candidates found."
589 |         val content = candidates.getJSONObject(0).optJSONObject("content") ?: return "AI Error: No content found."
590 |         val parts = content.optJSONArray("parts") ?: return "AI Error: No parts found."
591 |         
592 |         var finalResponse = ""
593 |         
594 |         for (i in 0 until parts.length()) {
595 |             val part = parts.getJSONObject(i)
596 |             
597 |             if (part.has("text")) {
598 |                 finalResponse += part.getString("text") + "\n"
599 |             }
600 |             
601 |             if (part.has("functionCall")) {
602 |                 val call = part.getJSONObject("functionCall")
603 |                 if (call.getString("name") == "execute_python_code") {
