4549 |     function filterDataset(items, tab) {
4550 |         const f = filters[tab];
4551 |         const now = Date.now();
4552 | 
4553 |         return items.filter(item => {
4554 |             // 1. Time Filter
4555 |             if (f.time !== 'all') {
4556 |                 const ts = new Date(item.created_at).getTime();
4557 |                 const diff = now - ts;
4558 |                 if (f.time === 'hour' && diff > 3600000) return false;
4559 |                 if (f.time === 'today' && diff > 86400000) return false;
4560 |                 if (f.time === 'week' && diff > 604800000) return false;
4561 |             }
4562 | 
4563 |             // 2. File Filter
4564 |             if (f.files.length > 0) {
4565 |                 let touchedFiles = [];
4566 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
4567 |                 if (tab === 'patcher') {
4568 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
4569 |                     touchedFiles = (item.results || []).map(r => r.file);
4570 |                 }
4571 |                 if (tab === 'cicd') {
4572 |                     const match = dbHistory.find(h => h.sha === item.head_commit.id);
4573 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
4574 |                 }
4575 |                 // Filter out empty paths
4576 |                 touchedFiles = touchedFiles.filter(p => p !== '');
4577 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
4578 |             }
4579 |             return true;
4580 |         });
4581 |     }
