4871 |     // --- GENERIC UI ---
4872 |     function formatBytes(bytes) {
4873 |         if (!bytes) return '0 B';
4874 |         const k = 1024;
4875 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4876 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4877 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4878 |     }
