4880 |     function timeAgo(dateString) {
4881 |         const date = new Date(dateString);
4882 |         const now = new Date();
4883 |         const seconds = Math.floor((now - date) / 1000);
4884 |         if (seconds < 10) return 'just now';
4885 |         if (seconds < 60) return seconds + 's ago';
4886 |         const minutes = Math.floor(seconds / 60);
4887 |         if (minutes < 60) return minutes + 'm ago';
4888 |         const hours = Math.floor(minutes / 60);
4889 |         if (hours < 24) return hours + 'h ago';
4890 |         return date.toLocaleDateString();
4891 |     }
