6239 |         diffRight.setValue("Loading...", -1);
6240 | 
6241 |         try {
6242 |             let leftContent = "", rightContent = "";
6243 | 
6244 |             if (forcedLeft !== null && forcedRight !== null) {
6245 |                 leftContent = forcedLeft;
6246 |                 rightContent = forcedRight;
6247 |             } else {
6248 |                 const rightRef = data.commit_sha || 'HEAD';
