6280 | 
6281 |             const Range = ace.require('ace/range').Range;
6282 | 
6283 |             // Helper to get Range from String Index
6284 |             const getRangeFromText = (session, searchText) => {
6285 |                 const fullText = session.getValue();
6286 |                 // 1. Try Exact Match
6287 |                 let startIdx = fullText.indexOf(searchText);
6288 |                 
6289 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
6290 |                 if (startIdx === -1) {
6291 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
6292 |                     startIdx = clean(fullText).indexOf(clean(searchText));
