6295 |                 if (startIdx !== -1) {
6296 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
6297 |                     const startRow = linesBefore.length - 1;
6298 |                     const startCol = linesBefore[startRow].length;
6299 |                     const linesInSearch = searchText.split('\n');
6300 |                     const endRow = startRow + linesInSearch.length - 1;
6301 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
6302 |                     return new Range(startRow, startCol, endRow, endCol);
6303 |                 }
6304 |                 return null;
6305 |             };
6306 |             
6307 |             const searchRemove = data.op.find_block || data.op.anchor;
6308 |             if(searchRemove) {
6309 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
6310 |                 if(range) {
