7248 |     function extractTableNames(sql) {
7249 |         if (!sql) return [];
7250 |         const tables = [];
7251 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7252 |         
7253 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7254 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7255 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7256 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7257 | 
7258 |         let match;
7259 |         while ((match = fromRegex.exec(sql)) !== null) {
7260 |             const name = match[1];
7261 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7262 |                 tables.push(name);
7263 |             }
7264 |         }
7265 |         
7266 |         while ((match = metaRegex.exec(sql)) !== null) {
7267 |             const name = match[1];
7268 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7269 |                 tables.push(name);
7270 |             }
7271 |         }
7272 | 
7273 |         return tables;
7274 |     }
