7276 |     function convertToCSV(resultObj) {
7277 |         const data = resultObj.data || [];
7278 |         if (!data.length) return '';
7279 |         
7280 |         const tables = extractTableNames(resultObj.sql);
7281 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7282 | 
7283 |         const headers = Object.keys(data[0]);
7284 |         const rows = data.map(row => 
7285 |             headers.map(header => {
7286 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7287 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7288 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7289 |             }).join(',')
7290 |         );
7291 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7292 |     }
