package com.conduit.app

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONArray
import org.json.JSONObject
import com.chaquo.python.Python

object SupabaseClient {
    private val client = OkHttpClient()
    private const val BASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/gemini-handler"

    suspend fun callConduitAction(payload: JSONObject): String = withContext(Dispatchers.IO) {
        val body = payload.toString().toRequestBody("application/json".toMediaType())
        val request = Request.Builder()
            .url(BASE_URL)
            .post(body)
            .build()
        try { 
            client.newCall(request).execute().use { it.body?.string() ?: "" } 
        } catch (e: Exception) { 
            "Error: \${e.message}" 
        }
    }

    suspend fun fetchSessionsFromSupabase(): List<Pair<String, String>> {
        val raw = callConduitAction(JSONObject().put("action", "list_sessions"))
        val list = mutableListOf<Pair<String, String>>()
        try {
            val arr = JSONArray(raw)
            for (i in 0 until arr.length()) {
                val obj = arr.getJSONObject(i)
                list.add(obj.getString("id") to obj.getString("title"))
            }
        } catch (e: Exception) {}
        return list
    }

    suspend fun fetchHistoryForSession(sessionId: String): List<Message> {
        val raw = callConduitAction(JSONObject().put("action", "fetch_history").put("session_id", sessionId))
        val list = mutableListOf<Message>()
        try {
            val arr = JSONArray(raw)
            for (i in 0 until arr.length()) {
                val obj = arr.getJSONObject(i)
                val isAi = obj.getString("sender") == "ai"
                list.add(Message(System.currentTimeMillis() + i, if (isAi) "AI" else "User", obj.getString("content"), isAi))
            }
        } catch (e: Exception) {}
        return list
    }

    suspend fun createNewSessionInSupabase(): String? {
        val raw = callConduitAction(JSONObject().put("action", "create_session"))
        return try { JSONObject(raw).getString("id") } catch (e: Exception) { null }
    }

    suspend fun deleteSessionFromSupabase(sessionId: String): Boolean {
        val raw = callConduitAction(JSONObject().put("action", "delete_session").put("session_id", sessionId))
        return raw.contains("true")
    }

    suspend fun callGeminiEdgeFunction(prompt: String, sessionId: String?): String {
        val python = Python.getInstance()
        val executor = python.getModule("executor")

        val payload = JSONObject().apply {
            put("action", "chat")
            put("prompt", prompt)
            if (sessionId != null) put("session_id", sessionId)
        }

        val raw = callConduitAction(payload)

        try {
            val jsonResp = JSONObject(raw)
            val candidates = jsonResp.optJSONArray("candidates") ?: return "AI Error: No candidates found."
            val content = candidates.getJSONObject(0).optJSONObject("content") ?: return "AI Error: No content found."
            val parts = content.optJSONArray("parts") ?: return "AI Error: No parts found."

            var finalResponse = ""

            for (i in 0 until parts.length()) {
                val part = parts.getJSONObject(i)

                if (part.has("text")) {
                    finalResponse += part.getString("text") + "\n"
                }

                if (part.has("functionCall")) {
                    val call = part.getJSONObject("functionCall")
                    if (call.getString("name") == "execute_python_code") {
                        val args = call.optJSONObject("args")
                        val code = args?.optString("code") ?: ""
                        if (code.isNotEmpty()) {
                            val result = withContext(Dispatchers.IO) { 
                                executor.callAttr("run_code", code).toString() 
                            }
                            finalResponse += "|||PY_RES|||\$result"
                        }
                    }
                }
            }
            return finalResponse.trim().ifEmpty { "AI returned an empty response." }
        } catch (e: Exception) {
            return "Processing Error: \${e.message}"
        }
    }
}

