@Composable
fun ChatBubble(sender: String, message: String, isAi: Boolean) {
    var isExpanded by remember { mutableStateOf(false) }
    val parts = message.split("|||PY_RES|||")
    val displayMsg = parts[0]
    val executionResult = if (parts.size > 1) parts[1] else null

    Column(
        modifier = Modifier.padding(vertical = 4.dp).fillMaxWidth(),
        horizontalAlignment = if (isAi) Alignment.Start else Alignment.End
    ) {
        Row(verticalAlignment = Alignment.Bottom) {
            if (isAi) {
                Icon(
                    Icons.Default.SmartToy,
                    contentDescription = null,
                    modifier = Modifier.size(24.dp).padding(end = 4.dp),
                    tint = MaterialTheme.colorScheme.primary
                )
            }
            Column(
                modifier = Modifier
                    .widthIn(max = 300.dp)
                    .background(
                        if (isAi) MaterialTheme.colorScheme.surface else MaterialTheme.colorScheme.secondary,
                        RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomStart = if (isAi) 4.dp else 16.dp, bottomEnd = if (isAi) 16.dp else 4.dp)
                    )
                    .border(
                        1.dp, 
                        if (isAi) Color.White.copy(alpha = 0.1f) else Color.Transparent,
                        RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomStart = if (isAi) 4.dp else 16.dp, bottomEnd = if (isAi) 16.dp else 4.dp)
                    )
                    .padding(12.dp)
                    .animateContentSize()
            ) {
                val textParts = displayMsg.split("`")
                val annotatedString = buildAnnotatedString {
                    textParts.forEachIndexed { index, part ->
                        if (index % 2 == 1) {
                            withStyle(style = SpanStyle(
                                fontFamily = FontFamily.Monospace,
                                background = Color.Black.copy(alpha = 0.4f),
                                color = Color(0xFF80CBC4)
                            )) {
                                append(part)
                            }
                        } else {
                            append(part)
                        }
                    }
                }
                Text(text = annotatedString, color = Color.White)

                if (executionResult != null) {
                    Spacer(modifier = Modifier.height(8.dp))
                    Surface(
                        modifier = Modifier
                            .fillMaxWidth()
                            .border(1.dp, Color.White.copy(alpha = 0.1f), RoundedCornerShape(8.dp)),
                        color = Color.Black.copy(alpha = 0.3f),
                        shape = RoundedCornerShape(8.dp)
                    ) {
                        Column(modifier = Modifier.padding(8.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(Icons.Default.Terminal, null, tint = Color(0xFF00FF00), modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Execution Result", style = MaterialTheme.typography.labelMedium, color = Color(0xFF00FF00))
                                }
                                TextButton(onClick = { isExpanded = !isExpanded }) {
                                    Text(if (isExpanded) "Collapse" else "Expand", style = MaterialTheme.typography.labelSmall)
                                    Icon(if (isExpanded) Icons.Default.ExpandLess else Icons.Default.ExpandMore, null, modifier = Modifier.size(16.dp))
                                }
                            }

                            if (isExpanded) {
                                HorizontalDivider(modifier = Modifier.padding(vertical = 4.dp), color = Color.White.copy(alpha = 0.1f))
                                Text(
                                    text = executionResult,
                                    color = Color(0xFF00FF00).copy(alpha = 0.8f),
                                    fontFamily = FontFamily.Monospace,
                                    style = MaterialTheme.typography.bodySmall,
                                    modifier = Modifier.padding(top = 4.dp)
                                )
                            } else {
                                Text(
                                    text = executionResult.take(50) + if (executionResult.length > 50) "..." else "",
                                    color = Color.Gray,
                                    style = MaterialTheme.typography.labelSmall,
                                    fontFamily = FontFamily.Monospace
                                )
                            }
                        }
                    }
                }
            }
        }

        if (isAi) {
            val context = LocalContext.current
            Row(horizontalArrangement = Arrangement.spacedBy(16.dp), modifier = Modifier.padding(top = 4.dp, start = 4.dp)) {
                Text(
                    "Copy Output", 
                    style = MaterialTheme.typography.labelSmall, 
                    color = Color.Gray, 
                    modifier = Modifier.clickable {
                        val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
                        val clip = ClipData.newPlainText("AI Response", message)
                        clipboard.setPrimaryClip(clip)
                        Toast.makeText(context, "Copied to clipboard", Toast.LENGTH_SHORT).show()
                    }
                )
                Text("Retry", style = MaterialTheme.typography.labelSmall, color = Color.Gray)
            }
        }
    }
}

