suspend fun callConduitAction(payload: JSONObject): String = withContext(Dispatchers.IO) {
    val requestBody = payload.toString().toRequestBody("application/json".toMediaType())
    val request = Request.Builder()
        .url(BASE_URL)
        .post(requestBody)
        .build()
    try { 
        client.newCall(request).execute().use { response ->
            val rawBody = response.body?.string() ?: ""
            if (!response.isSuccessful && !rawBody.trim().startsWith("{")) {
                // Wrap non-JSON error messages from server
                JSONObject().put("error", rawBody).toString()
            } else {
                rawBody
            }
        }
    } catch (e: Exception) { 
        JSONObject().put("error", "Network failure: ${e.message}").toString()
    }
}

