4856 |     // --- GENERIC UI ---
4857 |     function formatBytes(bytes) {
4858 |         if (!bytes) return '0 B';
4859 |         const k = 1024;
4860 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4861 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4862 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4863 |     }
