4865 |     function timeAgo(dateString) {
4866 |         const date = new Date(dateString);
4867 |         const now = new Date();
4868 |         const seconds = Math.floor((now - date) / 1000);
4869 |         if (seconds < 10) return 'just now';
4870 |         if (seconds < 60) return seconds + 's ago';
4871 |         const minutes = Math.floor(seconds / 60);
4872 |         if (minutes < 60) return minutes + 'm ago';
4873 |         const hours = Math.floor(minutes / 60);
4874 |         if (hours < 24) return hours + 'h ago';
4875 |         return date.toLocaleDateString();
4876 |     }
