6206 |         if(!diffLeft) {
6207 |             diffLeft = ace.edit("diff-left");
6208 |             diffLeft.setTheme("ace/theme/tomorrow_night_bright");
6209 |             diffLeft.setReadOnly(true);
6210 |             diffLeft.setOption("showPrintMargin", false);
