6213 |             diffRight.setTheme("ace/theme/tomorrow_night_bright");
6214 |             diffRight.setReadOnly(true);
6215 |             diffRight.setOption("showPrintMargin", false);
6216 | 
6217 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
6218 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
6219 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
6220 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
6221 |         }
6222 | 
6223 |         diffLeft.setValue("Loading...", -1);
6224 |         diffRight.setValue("Loading...", -1);
6225 | 
6226 |         try {
6227 |             let leftContent = "", rightContent = "";
6228 | 
6229 |             if (forcedLeft !== null && forcedRight !== null) {
6230 |                 leftContent = forcedLeft;
6231 |                 rightContent = forcedRight;
6232 |             } else {
6233 |                 const rightRef = data.commit_sha || 'HEAD';
6234 |                 const leftRef = rightRef + '^';
6235 | 
6236 |                 const fetchFile = async (ref) => {
6237 |                     const res = await fetch(CONFIG.funcUrl, {
6238 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
6239 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
6240 |                     });
6241 |                     const d = await res.json();
6242 |                     return d.content ? b64DecodeUnicode(d.content) : '';
6243 |                 };
6244 | 
6245 |                 const results = await Promise.all([
6246 |                     fetchFile(leftRef).catch(() => ""),
6247 |                     fetchFile(rightRef).catch(() => "")
6248 |                 ]);
6249 |                 leftContent = results[0];
6250 |                 rightContent = results[1];
6251 |             }
6252 | 
6253 |             let mode = "ace/mode/text";
6254 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
6255 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
6256 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
6257 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
6258 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
6259 |             
6260 |             diffLeft.session.setMode(mode);
6261 |             diffLeft.setValue(leftContent, -1);
6262 |             
6263 |             diffRight.session.setMode(mode);
6264 |             diffRight.setValue(rightContent, -1);
6265 | 
6266 |             const Range = ace.require('ace/range').Range;
6267 | 
6268 |             // Helper to get Range from String Index
6269 |             const getRangeFromText = (session, searchText) => {
6270 |                 const fullText = session.getValue();
6271 |                 // 1. Try Exact Match
6272 |                 let startIdx = fullText.indexOf(searchText);
6273 |                 
6274 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
6275 |                 if (startIdx === -1) {
6276 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
6277 |                     startIdx = clean(fullText).indexOf(clean(searchText));
6278 |                 }
6279 | 
6280 |                 if (startIdx !== -1) {
6281 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
6282 |                     const startRow = linesBefore.length - 1;
6283 |                     const startCol = linesBefore[startRow].length;
6284 |                     const linesInSearch = searchText.split('\n');
6285 |                     const endRow = startRow + linesInSearch.length - 1;
6286 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
6287 |                     return new Range(startRow, startCol, endRow, endCol);
6288 |                 }
6289 |                 return null;
6290 |             };
6291 |             
6292 |             const searchRemove = data.op.find_block || data.op.anchor;
6293 |             if(searchRemove) {
6294 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
6295 |                 if(range) {
6296 |                     diffLeft.session.addMarker(range, "marker-remove", "fullLine");
6297 |                     diffLeft.scrollToLine(range.start.row, true, true, function() {});
6298 |                 }
6299 |             }
6300 | 
6301 |             const searchAdd = data.op.replace_with || data.op.content;
6302 |             if(searchAdd) {
6303 |                 const range = getRangeFromText(diffRight.session, String(searchAdd));
6304 |                 if(range) {
6305 |                     diffRight.session.addMarker(range, "marker-add", "fullLine");
6306 |                     diffRight.scrollToLine(range.start.row, true, true, function() {});
6307 |                 }
6308 |             }
6309 | 
6310 |         } catch(e) {
6311 |             diffLeft.setValue("Error: " + e.message, -1);
6312 |         }
6313 |     }
