6419 |         if (!checkboxes.length) return;
6420 | 
6421 |         const idsToDelete = checkboxes.map(cb => cb.value);
6422 |         
6423 |         // Find the oldest record among the selection to determine rollback target
6424 |         // dbHistory is sorted newest -> oldest
6425 |         let oldestSelectedIndex = -1;
6426 |         checkboxes.forEach(cb => {
6427 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
6428 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
6429 |         });
6430 | 
6431 |         // The target is the first record older than our selection that isn't also being deleted
6432 |         let rollbackTarget = null;
6433 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
6434 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
6435 |                 rollbackTarget = dbHistory[i];
6436 |                 break;
6437 |             }
6438 |         }
6439 | 
6440 |         let msg = `Delete ${checkboxes.length} selected records?`;
6441 |         if (rollbackTarget) {
