7233 |     function extractTableNames(sql) {
7234 |         if (!sql) return [];
7235 |         const tables = [];
7236 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7237 |         
7238 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7239 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7240 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7241 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7242 | 
7243 |         let match;
7244 |         while ((match = fromRegex.exec(sql)) !== null) {
7245 |             const name = match[1];
7246 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7247 |                 tables.push(name);
7248 |             }
7249 |         }
7250 |         
7251 |         while ((match = metaRegex.exec(sql)) !== null) {
7252 |             const name = match[1];
7253 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7254 |                 tables.push(name);
7255 |             }
7256 |         }
7257 | 
7258 |         return tables;
7259 |     }
