7261 |     function convertToCSV(resultObj) {
7262 |         const data = resultObj.data || [];
7263 |         if (!data.length) return '';
7264 |         
7265 |         const tables = extractTableNames(resultObj.sql);
7266 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7267 | 
7268 |         const headers = Object.keys(data[0]);
7269 |         const rows = data.map(row => 
7270 |             headers.map(header => {
7271 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7272 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7273 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7274 |             }).join(',')
7275 |         );
7276 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7277 |     }
