4877 |     function formatBytes(bytes) {
4878 |         if (!bytes) return '0 B';
4879 |         const k = 1024;
4880 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4881 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4882 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4883 |     }
