4885 |     function timeAgo(dateString) {
4886 |         const date = new Date(dateString);
4887 |         const now = new Date();
4888 |         const seconds = Math.floor((now - date) / 1000);
4889 |         if (seconds < 10) return 'just now';
4890 |         if (seconds < 60) return seconds + 's ago';
4891 |         const minutes = Math.floor(seconds / 60);
4892 |         if (minutes < 60) return minutes + 'm ago';
4893 |         const hours = Math.floor(minutes / 60);
4894 |         if (hours < 24) return hours + 'h ago';
4895 |         return date.toLocaleDateString();
4896 |     }
