5095 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5096 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5097 |         
5098 |         const navItems = document.querySelectorAll('.nav-item');
5099 |         switchTab(tabId, navItems[navIndex]);
5100 | 
5101 |         const scrollContainer = document.querySelector('.main-view');
5102 |         let retryCount = 0;
5103 |         const MAX_RETRIES = 5;
5104 | 
5105 |         const attemptNavigation = async () => {
5106 |             const element = document.querySelector(selector);
5107 |             
5108 |             if (element) {
5109 |                 console.log("[DeepJump] Element found. Scrolling...");
5110 |                 
5111 |                 // Wait for any tab transition animations
5112 |                 await new Promise(r => setTimeout(r, 300));
5113 | 
5114 |                 let offsetTop = 0;
5115 |                 let curr = element;
5116 |                 while (curr && curr !== scrollContainer) {
5117 |                     offsetTop += curr.offsetTop;
5118 |                     curr = curr.offsetParent;
5119 |                 }
5120 | 
5121 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5122 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5123 | 
5124 |                 // Visual Highlight
5125 |                 element.style.transition = 'all 0.5s ease';
5126 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5127 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5128 |                 setTimeout(() => {
5129 |                     element.style.backgroundColor = '';
5130 |                     element.style.boxShadow = '';
5131 |                 }, 3000);
5132 |                 
5133 |                 console.groupEnd();
5134 |                 return true;
5135 |             }
5136 | 
5137 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5138 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5139 |                 retryCount++;
5140 |                 showGlobalToast("🔍 Searching deeper...");
5141 |                 
5142 |                 await loadMoreFn(); 
5143 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5144 |                 return attemptNavigation();
5145 |             }
5146 | 
5147 |             console.error("[DeepJump] Failed: Element not found after retries.");
5148 |             showGlobalToast("Entry not found in recent history.", true);
5149 |             console.groupEnd();
5150 |             return false;
5151 |         };
5152 | 
5153 |         setTimeout(attemptNavigation, 100);
