5964 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
5965 |                         const content = cleanChunk.substring(firstLineEnd + 1);
5966 |                         if (path) pendingImportFiles.push({ path, content });
5967 |                     }
5968 |                 });
5969 |             } 
5970 |             else {
5971 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
5972 |             }
