7253 |     function extractTableNames(sql) {
7254 |         if (!sql) return [];
7255 |         const tables = [];
7256 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7257 |         
7258 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7259 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7260 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7261 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7262 | 
7263 |         let match;
7264 |         while ((match = fromRegex.exec(sql)) !== null) {
7265 |             const name = match[1];
7266 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7267 |                 tables.push(name);
7268 |             }
7269 |         }
7270 |         
7271 |         while ((match = metaRegex.exec(sql)) !== null) {
7272 |             const name = match[1];
7273 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7274 |                 tables.push(name);
7275 |             }
7276 |         }
7277 | 
7278 |         return tables;
7279 |     }
7280 | 
7281 |     function convertToCSV(resultObj) {
7282 |         const data = resultObj.data || [];
7283 |         if (!data.length) return '';
7284 |         
7285 |         const tables = extractTableNames(resultObj.sql);
7286 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7287 | 
7288 |         const headers = Object.keys(data[0]);
7289 |         const rows = data.map(row => 
7290 |             headers.map(header => {
7291 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7292 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7293 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7294 |             }).join(',')
7295 |         );
7296 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7297 |     }
