async function runSqlQuery() {
    if (isPerformingAction) return;
    const sql = document.getElementById('sqlEditor').value;
    if (!sql.trim()) return;

    saveSqlState(); 
    const loader = document.getElementById('sqlLoader');
    const output = document.getElementById('sqlResultOutput');
    const statusText = document.getElementById('sqlStatusText');
    const statusDot = document.getElementById('sqlStatusDot');
    const copyBtn = document.getElementById('sqlCopyBtn');
    const dlBtn = document.getElementById('sqlDownloadBtn');
    const filterInput = document.getElementById('sqlResultFilter');

    loader.classList.remove('hidden');
    copyBtn.classList.add('hidden');
    dlBtn.classList.add('hidden');
    if(filterInput) filterInput.classList.add('hidden');

    isPerformingAction = true;
    statusDot.className = "w-1.5 h-1.5 rounded-full bg-yellow-500 animate-pulse";
    statusText.innerText = "Running...";

    try {
        const result = await callSqlEdgeFunction(sql);
        lastSqlResultData = {
            data: result.data,
            sql: sql,
            count: result.count
        };
        renderSqlResultTable(result.data);

        statusText.innerText = 'Success: ' + (result.count || result.data.length) + ' rows';
        statusDot.className = "w-1.5 h-1.5 rounded-full bg-green-500";

        if(filterInput) {
            filterInput.classList.remove('hidden');
            filterInput.value = '';
        }
        copyBtn.innerText = 'COPY CSV';
        copyBtn.classList.remove('hidden');
        dlBtn.classList.remove('hidden');
    } catch (err) {
        lastSqlResultData = { isError: true, message: err.message };
        output.innerHTML = `<div class="p-6 bg-red-500/5 text-red-400 m-4 rounded-xl border border-red-500/20 font-mono text-xs"><p class="font-bold mb-1 uppercase">[Error]</p>${err.message}</div>`;
        statusText.innerText = "Query Failed";
        statusDot.className = "w-1.5 h-1.5 rounded-full bg-red-500";
        copyBtn.innerText = 'COPY ERROR';
        copyBtn.classList.remove('hidden');
    } finally {
        isPerformingAction = false;
        loader.classList.add('hidden');
    }
}

