1797 |                         <pre style="white-space:pre-wrap; word-break:break-all; font-family:'JetBrains Mono'; font-size:10px; color:#ccc; margin:0;">${escapeHtml(msg)}</pre>
1798 |                     </div>
1799 |                 </details>`;
1800 |         }
1801 |         
1802 |         container.appendChild(row);
1803 |         if (container.scrollHeight - container.scrollTop < 1000) container.scrollTop = container.scrollHeight;
1804 |     }
