2110 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2111 |     function applyLocalPatch(content, ops) {
2112 |         let lines = content.split('\n');
2113 |         let logs = [];
2114 |         let success = true;
2115 | 
2116 |         if (typeof ops === 'string') {
2117 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2118 |         }
2119 | 
2120 |         ops.forEach(op => {
2121 |             if (op.action === 'comment') return;
2122 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2123 |             
2124 |             if (op.action === 'replace_block') {
2125 |                 // Strategy 1: Exact String Match (Fastest)
2126 |                 const currentStr = lines.join('\n');
2127 |                 if (currentStr.includes(op.find_block)) {
2128 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2129 |                     logs.push('Exact match applied');
2130 |                     return;
2131 |                 }
2132 | 
2133 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2134 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2135 |                 if (searchLines.length === 0) return;
2136 | 
2137 |                 let matchStart = -1;
2138 |                 let matchEnd = -1;
2139 | 
2140 |                 // Scan file lines
2141 |                 for (let i = 0; i < lines.length; i++) {
2142 |                     // If first line matches (ignoring whitespace)
2143 |                     if (lines[i].trim() === searchLines[0]) {
2144 |                         // Check subsequent lines
2145 |                         let allMatch = true;
2146 |                         let fileOffset = 0;
2147 |                         let searchOffset = 1;
2148 |                         
2149 |                         while (searchOffset < searchLines.length) {
2150 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2151 |                             const nextFile = lines[i + fileOffset + 1].trim();
2152 |                             // Skip empty lines in file if they aren't in search block
2153 |                             if (nextFile === '') {
2154 |                                 fileOffset++;
2155 |                                 continue;
2156 |                             }
2157 |                             if (nextFile !== searchLines[searchOffset]) {
2158 |                                 allMatch = false;
2159 |                                 break;
2160 |                             }
2161 |                             fileOffset++;
2162 |                             searchOffset++;
2163 |                         }
2164 | 
2165 |                         if (allMatch) {
2166 |                             matchStart = i;
2167 |                             matchEnd = i + fileOffset;
2168 |                             break;
2169 |                         }
2170 |                     }
2171 |                 }
2172 | 
2173 |                 if (matchStart !== -1) {
2174 |                     // Replace the range of lines
2175 |                     const replacement = op.replace_with.split('\n');
2176 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2177 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2178 |                 } else {
2179 |                     success = false;
2180 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2181 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2182 |                 }
2183 |             }
2184 |         });
2185 |         return { content: lines.join('\n'), success, logs };
2186 |     }
