4547 |             if (f.time !== 'all') {
4548 |                 const ts = new Date(item.created_at).getTime();
4549 |                 const diff = now - ts;
4550 |                 if (f.time === 'hour' && diff > 3600000) return false;
4551 |                 if (f.time === 'today' && diff > 86400000) return false;
4552 |                 if (f.time === 'week' && diff > 604800000) return false;
4553 |             }
4554 | 
4555 |             // 2. File Filter
4556 |             if (f.files.length > 0) {
4557 |                 let touchedFiles = [];
4558 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
4559 |                 if (tab === 'patcher') {
4560 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
4561 |                     touchedFiles = (item.results || []).map(r => r.file);
4562 |                 }
4563 |                 if (tab === 'cicd') {
4564 |                     const match = dbHistory.find(h => h.sha === item.head_commit.id);
4565 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
4566 |                 }
4567 |                 // Filter out empty paths
4568 |                 touchedFiles = touchedFiles.filter(p => p !== '');
4569 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
4570 |             }
4571 |             return true;
