4863 |     // --- GENERIC UI ---
4864 |     function formatBytes(bytes) {
4865 |         if (!bytes) return '0 B';
4866 |         const k = 1024;
4867 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4868 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4869 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4870 |     }
4871 | 
4872 |     function timeAgo(dateString) {
4873 |         const date = new Date(dateString);
4874 |         const now = new Date();
4875 |         const seconds = Math.floor((now - date) / 1000);
4876 |         if (seconds < 10) return 'just now';
4877 |         if (seconds < 60) return seconds + 's ago';
4878 |         const minutes = Math.floor(seconds / 60);
4879 |         if (minutes < 60) return minutes + 'm ago';
4880 |         const hours = Math.floor(minutes / 60);
4881 |         if (hours < 24) return hours + 'h ago';
4882 |         return date.toLocaleDateString();
4883 |     }
