5085 |         const navItems = document.querySelectorAll('.nav-item');
5086 |         switchTab(tabId, navItems[navIndex]);
5087 | 
5088 |         const scrollContainer = document.querySelector('.main-view');
5089 |         let retryCount = 0;
5090 |         const MAX_RETRIES = 5;
5091 | 
5092 |         const attemptNavigation = async () => {
5093 |             const element = document.querySelector(selector);
5094 |             
5095 |             if (element) {
5096 |                 console.log("[DeepJump] Element found. Scrolling...");
5097 |                 
5098 |                 // Wait for any tab transition animations
5099 |                 await new Promise(r => setTimeout(r, 300));
5100 | 
5101 |                 let offsetTop = 0;
5102 |                 let curr = element;
5103 |                 while (curr && curr !== scrollContainer) {
5104 |                     offsetTop += curr.offsetTop;
5105 |                     curr = curr.offsetParent;
5106 |                 }
5107 | 
5108 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5109 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5110 | 
5111 |                 // Visual Highlight
5112 |                 element.style.transition = 'all 0.5s ease';
5113 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5114 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5115 |                 setTimeout(() => {
5116 |                     element.style.backgroundColor = '';
5117 |                     element.style.boxShadow = '';
5118 |                 }, 3000);
5119 |                 
5120 |                 console.groupEnd();
5121 |                 return true;
5122 |             }
5123 | 
5124 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5125 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5126 |                 retryCount++;
5127 |                 showGlobalToast("🔍 Searching deeper...");
5128 |                 
5129 |                 await loadMoreFn(); 
5130 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5131 |                 return attemptNavigation();
5132 |             }
