5924 | 
5925 |         try {
5926 |             if (file.name.endsWith('.zip')) {
5927 |                 const zip = await JSZip.loadAsync(file);
5928 |                 const promises = [];
5929 |                 zip.forEach((relativePath, zipEntry) => {
