7240 |     function extractTableNames(sql) {
7241 |         if (!sql) return [];
7242 |         const tables = [];
7243 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7244 |         
7245 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7246 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7247 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7248 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7249 | 
7250 |         let match;
7251 |         while ((match = fromRegex.exec(sql)) !== null) {
7252 |             const name = match[1];
7253 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7254 |                 tables.push(name);
7255 |             }
7256 |         }
7257 |         
7258 |         while ((match = metaRegex.exec(sql)) !== null) {
7259 |             const name = match[1];
7260 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7261 |                 tables.push(name);
7262 |             }
7263 |         }
7264 | 
7265 |         return tables;
7266 |     }
