7268 |     function convertToCSV(resultObj) {
7269 |         const data = resultObj.data || [];
7270 |         if (!data.length) return '';
7271 |         
7272 |         const tables = extractTableNames(resultObj.sql);
7273 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7274 | 
7275 |         const headers = Object.keys(data[0]);
7276 |         const rows = data.map(row => 
7277 |             headers.map(header => {
7278 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7279 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7280 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7281 |             }).join(',')
7282 |         );
7283 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7284 |     }
